import * as t from "io-ts";
import { BaseIntent } from "./baseIntent";
import { intentTypes } from "./intentType";
import { RecipientEntry } from "./recipientEntry";

export const FeeAddressTransferIntent = t.intersection([
  BaseIntent,
  t.type({
    intentType: intentTypes.feeAddressTransfer,
    recipients: t.array(RecipientEntry),
  }),
]);

export type FeeAddressTransferIntent = t.TypeOf<
  typeof FeeAddressTransferIntent
>;
